// Apply threshold rules to the AI-classified alerts.
// An alert is approved for delivery when ALL of the following are true:
//   1. AI recommended send_alert = true
//   2. importance_score >= ALERT_IMPORTANCE_THRESHOLD (default: 60)
//   3. severity_score   >= ALERT_SEVERITY_THRESHOLD   (default: 50)
//   4. confidence_score >= ALERT_CONFIDENCE_THRESHOLD (default: 40)
//
// Trust-aware rules (per docs/architecture/trust-scoring.md):
//   - T4 sources are subject to per-topic severity caps
//   - Topics that exclude T4 (economy, health) reject T4 items entirely
//   - Topics that require confirmation for T4 mark items as pending
//   - Unknown-tier sources are treated as T4 with a severity cap of 30
//
// All persistable alerts are emitted via the main items stream so downstream
// modules that only expand input.items still receive pending-confirmation items.
// Each emitted item carries an explicit status plus confirmation_status.

const importanceThreshold = parseInt($vars.ALERT_IMPORTANCE_THRESHOLD || '60', 10);
const severityThreshold   = parseInt($vars.ALERT_SEVERITY_THRESHOLD   || '50', 10);
const confidenceThreshold = parseInt($vars.ALERT_CONFIDENCE_THRESHOLD || '40', 10);

// Per-topic T4 policy is injected from config/trust-rules.json via the
// TRUST_RULES_JSON workflow variable.  When the variable is absent, fall back
// to a built-in default so the workflow does not hard-fail during initial
// setup or local testing.
const DEFAULT_TOPIC_POLICIES = {
  crypto:     { t4Allowed: true,  severityCap: 60, canTrigger: true,  confirmationRequired: false },
  ai:         { t4Allowed: true,  severityCap: 50, canTrigger: true,  confirmationRequired: false },
  finance:    { t4Allowed: true,  severityCap: 30, canTrigger: false, confirmationRequired: true  },
  economy:    { t4Allowed: false, severityCap: 0,  canTrigger: false, confirmationRequired: false },
  health:     { t4Allowed: false, severityCap: 0,  canTrigger: false, confirmationRequired: false },
  energy:     { t4Allowed: true,  severityCap: 50, canTrigger: true,  confirmationRequired: true  },
  technology: { t4Allowed: true,  severityCap: 50, canTrigger: true,  confirmationRequired: false }
};

function toBoolean(value, defaultValue) {
  return typeof value === 'boolean' ? value : defaultValue;
}

function toNumber(value, defaultValue) {
  return typeof value === 'number' && Number.isFinite(value) ? value : defaultValue;
}

function normalizeTopicPolicy(raw) {
  if (!raw || typeof raw !== 'object') {
    return { t4Allowed: false, severityCap: 0, canTrigger: false, confirmationRequired: false };
  }
  return {
    t4Allowed:            toBoolean(raw.t4Allowed,            toBoolean(raw.t4_allowed, false)),
    severityCap:          toNumber(raw.severityCap,            toNumber(raw.severity_cap, 0)),
    canTrigger:           toBoolean(raw.canTrigger,            toBoolean(raw.can_trigger_alert, false)),
    confirmationRequired: toBoolean(raw.confirmationRequired,  toBoolean(raw.confirmation_required, false))
  };
}

let topicPolicies = DEFAULT_TOPIC_POLICIES;
const trustRulesJson = $vars.TRUST_RULES_JSON;
if (trustRulesJson) {
  try {
    const trustRules = JSON.parse(trustRulesJson);
    const raw = trustRules.topic_t4_policy || {};
    topicPolicies = {};
    for (const [slug, policy] of Object.entries(raw)) {
      topicPolicies[slug] = normalizeTopicPolicy(policy);
    }
  } catch (_) {
    // Fall back to defaults on parse error
    topicPolicies = DEFAULT_TOPIC_POLICIES;
  }
}

const DEFAULT_POLICY = { t4Allowed: false, severityCap: 0, canTrigger: false, confirmationRequired: false };
const UNKNOWN_SOURCE_SEVERITY_CAP = 30;

const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];

const approved = [];
const rejected = [];
const pendingConfirmation = [];

for (const item of items) {
  const trustTier = item.trust_tier || null;
  const isT4 = trustTier === 'T4';
  const isUnknownTier = trustTier === null;
  const isLowTrust = isT4 || isUnknownTier;
  const topicPolicy = topicPolicies[item.topic_slug] || DEFAULT_POLICY;

  // Rule: Reject T4/unknown items for topics that exclude T4 entirely
  if (isLowTrust && !topicPolicy.t4Allowed) {
    rejected.push(item.item_id);
    continue;
  }

  const rawSeverity = item.severity_score;
  let adjustedSeverity = rawSeverity;

  // Rule: Apply per-topic severity cap for T4 sources
  if (isT4 && topicPolicy.severityCap > 0) {
    adjustedSeverity = Math.min(adjustedSeverity, topicPolicy.severityCap);
  }

  // Rule: Apply strict severity cap for unknown-tier sources
  if (isUnknownTier) {
    adjustedSeverity = Math.min(adjustedSeverity, UNKNOWN_SOURCE_SEVERITY_CAP);
  }

  // Evaluate eligibility using raw severity so trust caps do not block
  // the pending path for topics that explicitly require confirmation
  // (e.g. finance where cap=30 < global severity threshold=50).
  const rawPasses =
    item.send_alert === true &&
    item.importance_score >= importanceThreshold &&
    rawSeverity           >= severityThreshold   &&
    item.confidence_score >= confidenceThreshold;

  const passes =
    item.send_alert === true &&
    item.importance_score >= importanceThreshold &&
    adjustedSeverity      >= severityThreshold   &&
    item.confidence_score >= confidenceThreshold;

  // Rule: T4 items that require confirmation are held as pending.
  // Use rawPasses so severity-capped items can still enter the pending path.
  if (rawPasses && isLowTrust && topicPolicy.confirmationRequired) {
    const eventDate = item.event_at ? item.event_at.slice(0, 10) : new Date().toISOString().slice(0, 10);
    pendingConfirmation.push({
      ...item,
      severity_score: adjustedSeverity,
      alert_id:       null,
      cluster_id:     null,
      date_key:       eventDate,
      channels:       ['telegram', 'discord'],
      status:         'pending_confirmation',
      confirmation_status: 'pending'
    });
    continue;
  }

  // Rule: T4 items where topic disallows independent triggering
  if (passes && isLowTrust && !topicPolicy.canTrigger) {
    rejected.push(item.item_id);
    continue;
  }

  if (passes) {
    const eventDate = item.event_at ? item.event_at.slice(0, 10) : new Date().toISOString().slice(0, 10);
    approved.push({
      ...item,
      severity_score: adjustedSeverity,
      alert_id:       null,
      cluster_id:     null,
      date_key:       eventDate,
      channels:       ['telegram', 'discord'],
      status:         'active',
      confirmation_status: isLowTrust ? 'unconfirmed' : 'confirmed'
    });
  } else {
    rejected.push(item.item_id);
  }
}

// Merge pending items into the main items stream so downstream modules
// (e.g. module 07 D1 persistence) receive all persistable alerts.
const persistableItems = approved.concat(pendingConfirmation);

return [{
  json: {
    items:                    persistableItems,
    pending_confirmation:     pendingConfirmation,
    rejected_count:           rejected.length,
    approved_count:           approved.length,
    pending_count:            pendingConfirmation.length
  }
}];
